const burger=document.querySelector(".burger-btn"),menu=document.querySelector(".menu"),loginButton=document.querySelector(".header__login"),loginPopupWindow=document.querySelector(".popup"),scrollButtons=document.querySelectorAll(".button"),freeTrialInput=document.querySelector(".popup-input");window.addEventListener("scroll",()=>{let e=document.querySelector(".header__nav");100<pageYOffset?e.classList.add("header__nav--fix"):e.classList.remove("header__nav--fix")}),burger.addEventListener("click",()=>{burger.classList.toggle("burger-btn--active"),menu.classList.toggle("menu--active")}),loginButton.addEventListener("click",()=>{loginPopupWindow.style.display="block",document.body.style.overflow="hidden"}),loginPopupWindow.addEventListener("click",e=>{e.target===loginPopupWindow&&(loginPopupWindow.style.display="none",document.body.style.overflow="")});let V=1;scrollButtons.forEach((t,e)=>{t.addEventListener("click",e=>{let o=window.pageYOffset,n=t.href.replace(/[^#]*(.*)/,"$1"),l=document.querySelector(n).getBoundingClientRect().top,r=null;requestAnimationFrame(function e(t){null===r&&(r=t);var t=t-r,t=l<0?Math.max(o-t/V,o+l):Math.min(o+t/V,o+l);window.scrollTo(0,t);t!=o+l?requestAnimationFrame(e):location.hash=n}),freeTrialInput.focus()})});